module traffic_light(
    input rst_n, input clk, input pass_request,
    output reg [7:0] clock,
    output reg red, yellow, green
);
    parameter idle = 2'b00, s1_red = 2'b01, s2_yellow = 2'b10, s3_green = 2'b11;
    reg [1:0] state;
    reg [7:0] p_red, p_yellow, p_green;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= idle;
            p_red <= 0;
            p_yellow <= 0;
            p_green <= 0;
        end else begin
            case (state)
                idle: begin
                    p_red <= 0;
                    p_yellow <= 0;
                    p_green <= 0;
                    state <= s1_red;
                end
                s1_red: begin
                    p_red <= 1;
                    if (clock == 3) begin
                        state <= s2_yellow;
                        p_red <= 0;
                    end else begin
                        state <= s1_red;
                    end
                end
                s2_yellow: begin
                    p_yellow <= 1;
                    if (clock == 3) begin
                        state <= s3_green;
                        p_yellow <= 0;
                    end else begin
                        state <= s2_yellow;
                    end
                end
                s3_green: begin
                    p_green <= 1;
                    if (clock == 3) begin
                        state <= s2_yellow;
                        p_green <= 0;
                    end else begin
                        state <= s3_green;
                    end
                end
        endcase
    end

    end // Auto-repaired
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            clock <= 0;
        end else begin
            if (clock == 0) begin
                clock <= 60;
            end else begin
                clock <= clock - 1;
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            red <= 0;
            yellow <= 0;
            green <= 0;
        end else begin
            red <= p_red;
            yellow <= p_yellow;
            green <= p_green;
        end
    end
endmodule
